    render(<AnimatedCounter value={1000000} />);
    expect(screen.getByText('1,000,000')).toBeInTheDocument();
  });
});

// jargon-text.test.tsx
import { render, screen } from '@testing-library/react';
import userEvent from '@testing-library/user-event';
import { JargonText } from './jargon-text';

describe('JargonText', () => {
  it('highlights known jargon terms', () => {
    render(<JargonText>The third alternative is key.</JargonText>);

    const term = screen.getByText('third alternative');
    expect(term).toHaveClass('jargon-term');
  });

  it('shows definition tooltip on hover', async () => {
    const user = userEvent.setup();
    render(<JargonText>The third alternative is key.</JargonText>);

    await user.hover(screen.getByText('third alternative'));

    await waitFor(() => {
      expect(screen.getByRole('tooltip')).toHaveTextContent(/§103/);
    });
  });
});
